#!/usr/bin/env bash
# Generated by pivota-spec init-dev-server
# Catalog entry: agent-synthesized
# Generator version: init-dev-server@1
#
# Stack: docker-compose (PHP/Apache + MariaDB + Solr) + Spring Boot backend (backend/)
# Multi-match detected: compose + java-spring → agent fallback (D-06)
#
# Edits ABOVE the END PIVOTA PREAMBLE marker are reset on regen.
# Edits BELOW the marker are preserved on regen.
#
# Why these choices (decision-trace; do not delete):
#   - `set -euo pipefail` not just `-e` — RESEARCH.md Pitfall 4 (silent pipe failures).
#   - `sha256sum` for lockfile hashing — RESEARCH.md "Don't hand-roll" (universal
#     coreutils, no extra dep vs blake3 / git hash-object / md5sum).
#   - Backoff 1s / 2s / 4s — Claude's Discretion per CONTEXT.md (small base, predictable).
#   - Log destination `/tmp/pivota-dev.log` — Open Question #4 resolved (always
#     writable inside Daytona sandboxes; matches existing convention).
#   - Agent fallback: compose + java-spring both matched; multi-match triggers agent
#     synthesis. Primary runtime is docker-compose (the Dockerfile + compose.yml declare
#     the full PHP/Apache/MariaDB/Solr stack). Spring Boot backend is treated as a
#     secondary service started after compose is up.
#   - docker compose up --build ensures the PHP app image is built on first boot
#     (the compose file has build: . for the app service).
#   - site_config.php is required before compose starts; seeded from
#     infra/site_config.docker.php if missing (per README installation step 1).
#   - No NODE_ENV=production or --omit=dev (N/A: no Node.js stack).
#   - DATABASE_URL injection-safe .env seeding is handled by the template block below.

set -euo pipefail

# === Bash version guard (RESEARCH.md Pitfall 8) ===
# `wait -n` (used by the multi-process variant) requires bash >= 4.3.
# Fail fast with a clear message; do not silently degrade.
if (( BASH_VERSINFO[0] < 4 )) || { (( BASH_VERSINFO[0] == 4 )) && (( BASH_VERSINFO[1] < 3 )); }; then
  echo "[pivota] bash 4.3+ required for 'wait -n'; found ${BASH_VERSION}" >&2
  exit 127
fi

# === D-11.4: tee stdout/stderr to /tmp/pivota-dev.log AND pass through ===
mkdir -p /tmp
exec > >(tee -a /tmp/pivota-dev.log) 2>&1
echo "[pivota] $(date -Iseconds) start-dev.sh begin (catalog: agent-synthesized)"

# === D-11.1 + D-11.2: per-stack 0.0.0.0 binding + host allowlist relaxation ===
# Compose services control their own bind addresses via the `ports:` block in
# the compose file. The app service publishes 8080:80, phpmyadmin 8081:80, solr
# 8983:8983, db 3307:3306. All use the short `"host:container"` form which
# Docker maps to 0.0.0.0 by default — no wrapper env var needed.
# Spring Boot (backend/) honours SERVER_ADDRESS for bind override.
export SERVER_ADDRESS=0.0.0.0

# === D-11.3: .env.example -> .env seed (platform-injection-safe) ===
if [[ ! -f .env && -f .env.example ]]; then
  echo "[pivota] seeding .env from .env.example (preserving platform-injected vars)"
  while IFS= read -r line || [[ -n "$line" ]]; do
    trimmed="${line#"${line%%[![:space:]]*}"}"
    if [[ "$trimmed" == \#* || -z "$trimmed" || "$trimmed" != *"="* ]]; then
      printf '%s\n' "$line"; continue
    fi
    key="${trimmed#export }"; key="${key%%=*}"; key="${key//[[:space:]]/}"
    if [[ -n "${!key+x}" ]]; then
      printf '# [pivota] %s omitted — provided by platform environment\n' "$key"
    else
      printf '%s\n' "$line"
    fi
  done < .env.example > .env
fi

# === Pre-exec: seed site_config.php if missing (required by docker-setup.sh) ===
if [[ ! -f crm/data/site_config.php && -f infra/site_config.docker.php ]]; then
  echo "[pivota] seeding crm/data/site_config.php from infra/site_config.docker.php"
  mkdir -p crm/data
  cp infra/site_config.docker.php crm/data/site_config.php
fi

# === JDK install for Spring Boot backend (backend/pom.xml present) ===
# Daytona base snapshot does not ship OpenJDK (RESEARCH.md Pitfall 7).
# Idempotent: skipped if `java` is already on PATH.
(command -v java >/dev/null 2>&1 \
    || (echo "[pivota] installing OpenJDK 21 (one-time, ~30s)" \
        && sudo apt-get update -qq \
        && sudo DEBIAN_FRONTEND=noninteractive apt-get install -y -qq openjdk-21-jdk-headless)) \
    && export JAVA_HOME=$(readlink -f $(command -v java) 2>/dev/null | sed -E "s%/bin/java$%%") \
    && echo "[pivota] JAVA_HOME=$JAVA_HOME"
export PATH="${JAVA_HOME}/bin:$PATH"

# === D-12: idempotent install via lockfile hash + presence check ===
# Primary stack is Docker Compose — no separate package install step needed;
# `docker compose up --build` pulls/builds images on first run.
# Spring Boot backend: no mvnw present; dependencies resolved by spring-boot:run.
# Lock file: docker-compose.yml (structural change sentinel for the compose stack)
SENTINEL="/tmp/pivota-setup-sentinel"
LOCK_FILE_PATH="docker-compose.yml"
INSTALL_PRESENCE_CHECK=""
INSTALL_CMD=""

if [[ -n "$LOCK_FILE_PATH" && -f "$LOCK_FILE_PATH" ]]; then
  CURRENT_HASH=$(sha256sum "$LOCK_FILE_PATH" | cut -d' ' -f1)
  PREVIOUS_HASH=$(cat "$SENTINEL" 2>/dev/null || echo "")
  if [[ "$CURRENT_HASH" != "$PREVIOUS_HASH" ]]; then
    echo "[pivota] compose file changed (or first boot); noting hash for drift detection"
    echo "$CURRENT_HASH" > "$SENTINEL"
  fi
fi

# === Multi-process: docker compose up --build  +  Spring Boot backend ===
# docker compose up --build handles the PHP/Apache/MariaDB/Solr stack.
# Spring Boot backend runs as a second process via ./mvnw spring-boot:run
# (falls back to mvn if mvnw is absent).
# Both are supervised via bash trap + background PIDs + wait -n (RESEARCH.md Pattern 3).

shutdown() {
  echo "[pivota] shutting down children"
  kill -TERM "${PIDS[@]}" 2>/dev/null || true
  # Brief grace period then SIGKILL stragglers (RESEARCH.md Pitfall 3)
  sleep 2
  kill -KILL "${PIDS[@]}" 2>/dev/null || true
  wait
}
trap shutdown SIGTERM SIGINT EXIT

declare -a PIDS=()

# --- Process 1: Docker Compose stack (PHP app + MariaDB + Solr + phpMyAdmin) ---
(
  cd '.' \
    && : \
    && exec bash -c 'docker compose up --build'
) 2>&1 | sed 's/^/[compose] /' &
PIDS+=($!)

# --- Process 2: Spring Boot backend ---
# Detect build wrapper; fall back to system mvn.
SPRING_CMD='mvn spring-boot:run -pl backend'
if [[ -f backend/mvnw ]]; then
  SPRING_CMD='cd backend && ./mvnw spring-boot:run'
elif command -v mvn >/dev/null 2>&1; then
  SPRING_CMD='cd backend && mvn spring-boot:run'
fi
(
  cd '.' \
    && export SERVER_ADDRESS=0.0.0.0 \
    && exec bash -c "$SPRING_CMD"
) 2>&1 | sed 's/^/[spring-boot] /' &
PIDS+=($!)

# Wait for ANY child to exit; if one dies the trap tears down siblings.
wait -n
EXIT_CODE=$?
shutdown
exit "$EXIT_CODE"

# Unreachable, but keep for analyzer happiness
exit 1
